Bash(DISPLAY=:99 python3 -c "
import logging, os, time
os.environ['DISPLAY'] = ':99'
logging.basicConfig\(level=logging.WARNING\)
from services.browser.browser_service import BrowserService
from services.auth.login_service import LoginService
from config.settings import NAUKRI_PROFILE_URL

browser = BrowserService\(\)
page = browser.launch\(\)
try:
    LoginService\(page\).ensure_logged_in\(\)
    page.goto\(NAUKRI_PROFILE_URL, wait_until='networkidle'\)
    time.sleep\(4\)
    print\('URL:', page.url\)
    elems = page.evaluate\('''\(\) => {
        // All inputs \(resume upload candidate\)
        const inputs = Array.from\(document.querySelectorAll\(\\"input\\"\)\).map\(el => \({
            id: el.id, type: el.type, cls: el.className.slice\(0,80\), accept: el.accept, name: el.name
        }\)\);
        // All elements with class containing edit/pencil/icon
        const editSpans = Array.from\(document.querySelectorAll\(\\"span, i, button\\"\)\).filter\(el =>
            el.className && \(el.className.includes\(\\"edit\\"\) || el.className.includes\(\\"pencil\\"\) || el.className.includes\(\\"Edit\\"\)\)
        \).slice\(0,20\).map\(el => \({
            tag: el.tagName, cls: el.className.slice\(0,100\), title: el.title, 
            parentCls: el.parentElement?.className?.slice\(0,80\),
            grandParentCls: el.parentElement?.parentElement?.className?.slice\(0,80\)
        }\)\);
        // Widget headers
        const widgetHeads = Array.from\(document.querySelectorAll\(\\"[class*=widgetHead], [class*=widget-head], [class*=section-head], [class*=sectionHead]\\"\)\).slice\(0,15\).map\(el => \({
            cls: el.className.slice\(0,100\), text: el.innerText?.slice\(0,60\)
        }\)\);
        return {inputs, editSpans, widgetHeads};
    }'''\)
    import json; print\(json.dumps\(elems, indent=2\)\)
finally:
    browser.close\(\)
" 2>&1)
